// Validate Input Structure
// Purpose:
// Validate a local validation context object containing:
// - input_data: candidate SDE input object
// - schema: SDE input schema

const inputData = $json.input_data;
const schema = $json.schema;

if (!inputData || typeof inputData !== "object" || Array.isArray(inputData)) {
  throw new Error("Validate Input Structure: input_data must be a top-level object.");
}

if (!schema || typeof schema !== "object" || Array.isArray(schema)) {
  throw new Error("Validate Input Structure: schema must be a top-level object.");
}

const errors = [];

// --- Helpers ---
function detectType(value) {
  if (Array.isArray(value)) return "array";
  if (value === null) return "null";
  return typeof value;
}

function addError(code, field, message, extra = {}) {
  errors.push({
    code,
    field,
    message,
    ...extra
  });
}

function pathJoin(base, key) {
  if (base === "") return key;
  if (String(key).startsWith("[")) return `${base}${key}`;
  return `${base}.${key}`;
}

function validateAgainstSchema(value, schemaNode, path = "") {
  if (!schemaNode || typeof schemaNode !== "object") {
    return;
  }

  // 1. Type check
  if (schemaNode.type) {
    const actualType = detectType(value);

    if (schemaNode.type === "object") {
      if (actualType !== "object") {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "input"} must be an object`,
          { expected_type: "object", actual_type: actualType }
        );
        return;
      }
    } else if (schemaNode.type === "array") {
      if (actualType !== "array") {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "input"} must be an array`,
          { expected_type: "array", actual_type: actualType }
        );
        return;
      }
    } else {
      if (actualType !== schemaNode.type) {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "value"} must be of type ${schemaNode.type}`,
          { expected_type: schemaNode.type, actual_type: actualType }
        );
        return;
      }
    }
  }

  // 2. const
  if ("const" in schemaNode) {
    if (value !== schemaNode.const) {
      addError(
        "INVALID_LITERAL_VALUE",
        path || "(root)",
        `${path || "value"} must be exactly '${schemaNode.const}'`,
        { expected: schemaNode.const, actual: value }
      );
    }
  }

  // 3. enum
  if (Array.isArray(schemaNode.enum)) {
    if (!schemaNode.enum.includes(value)) {
      addError(
        "INVALID_ENUM_VALUE",
        path || "(root)",
        `${path || "value"} must be one of: ${schemaNode.enum.join(", ")}`,
        { allowed_values: schemaNode.enum, actual: value }
      );
    }
  }

  // 4. string constraints
  if (schemaNode.type === "string") {
    if ("minLength" in schemaNode && typeof value === "string") {
      if (value.length < schemaNode.minLength) {
        addError(
          "MIN_LENGTH_VIOLATION",
          path || "(root)",
          `${path || "value"} must be at least ${schemaNode.minLength} characters long`,
          { min_length: schemaNode.minLength, actual_length: value.length }
        );
      }
    }

    if (typeof value === "string" && value.trim().length === 0) {
      addError(
        "EMPTY_STRING_NOT_ALLOWED",
        path || "(root)",
        `${path || "value"} must not be empty or whitespace-only`,
        { actual_value: value }
      );
    }
  }

  // 5. array constraints
  if (schemaNode.type === "array" && Array.isArray(value)) {
    if ("minItems" in schemaNode && value.length < schemaNode.minItems) {
      addError(
        "MIN_ITEMS_VIOLATION",
        path || "(root)",
        `${path || "array"} must contain at least ${schemaNode.minItems} items`,
        { min_items: schemaNode.minItems, actual_count: value.length }
      );
    }

    if (schemaNode.uniqueItems === true) {
      const seen = new Set();
      for (let i = 0; i < value.length; i++) {
        const itemKey = JSON.stringify(value[i]);
        if (seen.has(itemKey)) {
          addError(
            "DUPLICATE_ARRAY_ITEM",
            `${path}[${i}]`,
            `${path}[${i}] must be unique`,
            { actual_value: value[i] }
          );
        } else {
          seen.add(itemKey);
        }
      }
    }

    if (schemaNode.items) {
      for (let i = 0; i < value.length; i++) {
        validateAgainstSchema(value[i], schemaNode.items, `${path}[${i}]`);
      }
    }
  }

  // 6. object constraints
  if (schemaNode.type === "object" && value && typeof value === "object" && !Array.isArray(value)) {
    const props = schemaNode.properties || {};
    const required = Array.isArray(schemaNode.required) ? schemaNode.required : [];

    // Required fields
    for (const reqField of required) {
      if (!(reqField in value)) {
        addError(
          "MISSING_REQUIRED_FIELD",
          path ? pathJoin(path, reqField) : reqField,
          `Missing required field: ${path ? pathJoin(path, reqField) : reqField}`
        );
      }
    }

    // additionalProperties: false
    if (schemaNode.additionalProperties === false) {
      for (const key of Object.keys(value)) {
        if (!(key in props)) {
          addError(
            "UNEXPECTED_FIELD",
            path ? pathJoin(path, key) : key,
            `Unexpected field not allowed by schema: ${path ? pathJoin(path, key) : key}`,
            { actual_key: key }
          );
        }
      }
    }

    // Validate declared properties that are present
    for (const [key, propSchema] of Object.entries(props)) {
      if (key in value) {
        validateAgainstSchema(value[key], propSchema, path ? pathJoin(path, key) : key);
      }
    }
  }
}

// --- Run validation ---
validateAgainstSchema(inputData, schema, "");

// --- Final status ---
const validation_status = errors.length === 0 ? "PASS" : "FAIL";

// Emit original input plus validation result
return [
  {
    json: {
      ...inputData,
      input_validation: {
        validation_status,
        error_count: errors.length,
        errors
      }
    }
  }
];

const item = $input.first();
const data = item.json;

const inputValidation = data.input_validation || {};
const errors = Array.isArray(inputValidation.errors) ? inputValidation.errors : [];

function deriveTopLevelReasonCode(errors) {
  if (!errors.length) return "UNKNOWN_VALIDATION_FAILURE";

  const codes = errors.map(e => e.code);

  if (codes.includes("MISSING_REQUIRED_FIELD")) {
    return "INPUT_SCHEMA_VIOLATION";
  }

  if (
    codes.includes("INVALID_TYPE") ||
    codes.includes("INVALID_NONEMPTY_STRING") ||
    codes.includes("INVALID_ARRAY_ITEM") ||
    codes.includes("INVALID_ENUM_VALUE") ||
    codes.includes("INVALID_LITERAL_VALUE") ||
    codes.includes("MIN_LENGTH_VIOLATION") ||
    codes.includes("UNEXPECTED_FIELD") ||
    codes.includes("DUPLICATE_ARRAY_ITEM")
  ) {
    return "INPUT_SCHEMA_VIOLATION";
  }

  return "INPUT_VALIDATION_FAILED";
}

function buildSummary(errors) {
  if (!errors.length) {
    return "Input validation failed, but no structured violations were provided.";
  }

  if (errors.length === 1) {
    return errors[0].message;
  }

  return `Input validation failed with ${errors.length} violations.`;
}

const topLevelReasonCode = deriveTopLevelReasonCode(errors);
const summary = buildSummary(errors);

return [
  {
    json: {
      ...data,
      blocked_result: {
        status: "blocked",
        can_proceed: false,
        block_stage: "input_validation",
        reason_code: topLevelReasonCode,
        reason_summary: summary,
        violation_count: errors.length,
        violations: errors
      }
    }
  }
];

const item = $input.first();
const data = item.json;

return [
  {
    json: {
      run_status: "blocked",
      input_id: data.input_id ?? null,
      stage: "input_validation",
      blocked_result: data.blocked_result,
      timestamp_utc: new Date().toISOString()
    }
  }
];

return [
  {
    json: {
      "$schema": "https://json-schema.org/draft/2020-12/schema",
      "$id": "sde.output.schema.v0_1.json",
      "title": "Structured Discovery Engine Output Schema",
      "description": "Output contract for Structured Discovery Engine (SDE) v0.1. Defines the structured discovery question set emitted from a validated SDE input.",
      "type": "object",
      "additionalProperties": false,
      "required": [
        "sde_version",
        "output_id",
        "source_input_id",
        "question_groups"
      ],
      "properties": {
        "sde_version": {
          "type": "string",
          "const": "v0_1",
          "description": "Schema version for the Structured Discovery Engine output contract."
        },
        "output_id": {
          "type": "string",
          "minLength": 1,
          "description": "Unique identifier for the SDE output artifact."
        },
        "source_input_id": {
          "type": "string",
          "minLength": 1,
          "description": "Identifier of the input object from which this discovery artifact was generated."
        },
        "question_groups": {
          "type": "array",
          "minItems": 1,
          "description": "Structured discovery groups containing context-aware questions.",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "group_id",
              "group_name",
              "group_purpose",
              "questions"
            ],
            "properties": {
              "group_id": {
                "type": "string",
                "minLength": 1,
                "description": "Unique identifier for the question group."
              },
              "group_name": {
                "type": "string",
                "enum": [
                  "GOALS",
                  "SCOPE",
                  "CONSTRAINTS",
                  "STAKEHOLDERS",
                  "DATA_AND_SYSTEMS",
                  "RISKS",
                  "SUCCESS_CRITERIA",
                  "ASSUMPTIONS",
                  "OTHER"
                ],
                "description": "Normalized category name for the discovery group."
              },
              "group_purpose": {
                "type": "string",
                "minLength": 1,
                "description": "Human-readable explanation of why this question group exists."
              },
              "questions": {
                "type": "array",
                "minItems": 1,
                "description": "Questions belonging to this discovery group.",
                "items": {
                  "type": "object",
                  "additionalProperties": false,
                  "required": [
                    "question_id",
                    "question_text",
                    "question_intent",
                    "priority"
                  ],
                  "properties": {
                    "question_id": {
                      "type": "string",
                      "minLength": 1,
                      "description": "Unique identifier for the question within the output artifact."
                    },
                    "question_text": {
                      "type": "string",
                      "minLength": 1,
                      "description": "The actual discovery question to ask."
                    },
                    "question_intent": {
                      "type": "string",
                      "minLength": 1,
                      "description": "Why the question is being asked and what ambiguity it is intended to reduce."
                    },
                    "priority": {
                      "type": "string",
                      "enum": [
                        "HIGH",
                        "MEDIUM",
                        "LOW"
                      ],
                      "description": "Relative priority of the question for ambiguity reduction."
                    }
                  }
                }
              }
            }
          }
        },
        "ambiguity_flags": {
          "type": "array",
          "description": "Optional list of major ambiguity areas identified during discovery generation.",
          "items": {
            "type": "string",
            "minLength": 1
          },
          "uniqueItems": true
        },
        "completeness_notes": {
          "type": "array",
          "description": "Optional notes about obvious missing context, weak areas, or likely follow-up needs.",
          "items": {
            "type": "string",
            "minLength": 1
          }
        }
      }
    }
  }
];

// Prepare AI Generation Payload
// Purpose:
// Build the SDE AI generation runtime contract artifact from validated SDE input
// and the authoritative SDE output schema.

const validatedInput = $("Validate Input Structure").first().json;
const outputSchema = $("Load Output Schema").first().json;

// Safety check: only continue if validation passed
const validationStatus = validatedInput?.input_validation?.validation_status;
if (validationStatus !== "PASS") {
  throw new Error("Prepare AI Generation Payload received non-valid input. validation_status must be PASS.");
}

// Build reduced generation-safe input.
// Exclude runtime validation metadata from semantic input.
const generationInput = {
  sde_version: validatedInput.sde_version,
  input_id: validatedInput.input_id,
  problem_description: validatedInput.problem_description,
  business_context: validatedInput.business_context ?? null,
  desired_outcome: validatedInput.desired_outcome ?? null,
  domain: validatedInput.domain ?? null,
  stakeholders: validatedInput.stakeholders ?? [],
  known_constraints: validatedInput.known_constraints ?? [],
  desired_output_type: validatedInput.desired_output_type ?? null,
  notes: validatedInput.notes ?? null,
  source_metadata: validatedInput.source_metadata ?? null
};

// Derive output contract from schema
const topLevelRequired = Array.isArray(outputSchema.required) ? outputSchema.required : [];
const questionGroupSchema = outputSchema?.properties?.question_groups?.items || {};
const questionGroupRequired = Array.isArray(questionGroupSchema.required) ? questionGroupSchema.required : [];
const questionSchema = questionGroupSchema?.properties?.questions?.items || {};
const questionRequired = Array.isArray(questionSchema.required) ? questionSchema.required : [];

const allowedGroupNames =
  questionGroupSchema?.properties?.group_name?.enum ?? [];

const allowedPriorities =
  questionSchema?.properties?.priority?.enum ?? [];

const questionGroupMinItems =
  outputSchema?.properties?.question_groups?.minItems ?? 1;

const questionsMinItems =
  questionGroupSchema?.properties?.questions?.minItems ?? 1;

// Build runtime contract artifact
const ai_generation_payload = {
  artifact_type: "SDE_AI_GENERATION_PAYLOAD",
  artifact_version: "v0_1",
  operator_id: "uso.sde.generate_question_set",
  execution_mode: "DISCOVERY_ONLY",

  validated_input: generationInput,

  operator_constraints: {
    structured_json_required: true,
    schema_conformance_required: true,
    grouping_required: true,
    question_intent_required: true,
    priority_required: true,
    ambiguity_flags_allowed: true,
    completeness_notes_allowed: true,
    recommendations_allowed: false,
    execution_planning_allowed: false,
    implementation_steps_allowed: false,
    prose_outside_json_allowed: false,
    invented_facts_allowed: false
  },

  generation_objective: {
    goal: "REDUCE_AMBIGUITY",
    prefer_high_value_questions: true,
    require_context_awareness: true,
    require_non_generic_questions: true,
    include_desired_outcome_clarification: true,
    require_grouping_into_normalized_categories: true
  },

  output_contract: {
    schema_id: outputSchema.$id ?? "sde.output.schema.v0_1.json",
    schema_title: outputSchema.title ?? "Structured Discovery Engine Output Schema",
    required_top_level_fields: topLevelRequired,
    required_question_group_fields: questionGroupRequired,
    required_question_fields: questionRequired,
    allowed_group_names: allowedGroupNames,
    allowed_priority_values: allowedPriorities,
    question_group_min_items: questionGroupMinItems,
    questions_min_items: questionsMinItems
  }
};

return [
  {
    json: ai_generation_payload
  }
];

const item = $input.first();
const raw = item.json?.text;

// Basic presence/type check
if (typeof raw !== "string" || raw.trim().length === 0) {
  throw new Error("Parse AI Output: expected a non-empty string in item.json.text");
}

let cleaned = raw.trim();

// Remove markdown fences if the model ever returns them
if (cleaned.startsWith("```")) {
  cleaned = cleaned
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/\s*```$/, "")
    .trim();
}

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    `Parse AI Output: failed to parse model output as JSON. ${err.message}`
  );
}

// Ensure top-level parsed value is an object
if (parsed === null || Array.isArray(parsed) || typeof parsed !== "object") {
  throw new Error("Parse AI Output: parsed JSON must be a top-level object");
}

// Emit the parsed object directly
return [
  {
    json: parsed
  }
];

// Pull parsed AI response envelope from prior node
const parsedResponse = $("Parse AI Output").first().json;

// Pull output schema artifact from prior node
const schema = $("Load Output Schema").first().json;

const outputData = parsedResponse?.output;

if (!outputData || typeof outputData !== "object" || Array.isArray(outputData)) {
  throw new Error("Validate Output Structure: parsedResponse.output must be a top-level object");
}

if (!schema || typeof schema !== "object" || Array.isArray(schema)) {
  throw new Error("Validate Output Structure: schema must be a top-level object");
}

const errors = [];

// --- Helpers ---
function detectType(value) {
  if (Array.isArray(value)) return "array";
  if (value === null) return "null";
  return typeof value;
}

function addError(code, field, message, extra = {}) {
  errors.push({
    code,
    field,
    message,
    ...extra
  });
}

function pathJoin(base, key) {
  if (base === "") return key;
  if (String(key).startsWith("[")) return `${base}${key}`;
  return `${base}.${key}`;
}

function validateAgainstSchema(value, schemaNode, path = "") {
  if (!schemaNode || typeof schemaNode !== "object") {
    return;
  }

  if (schemaNode.type) {
    const actualType = detectType(value);

    if (schemaNode.type === "object") {
      if (actualType !== "object") {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "output"} must be an object`,
          { expected_type: "object", actual_type: actualType }
        );
        return;
      }
    } else if (schemaNode.type === "array") {
      if (actualType !== "array") {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "output"} must be an array`,
          { expected_type: "array", actual_type: actualType }
        );
        return;
      }
    } else {
      if (actualType !== schemaNode.type) {
        addError(
          "INVALID_TYPE",
          path || "(root)",
          `${path || "value"} must be of type ${schemaNode.type}`,
          { expected_type: schemaNode.type, actual_type: actualType }
        );
        return;
      }
    }
  }

  if ("const" in schemaNode) {
    if (value !== schemaNode.const) {
      addError(
        "INVALID_LITERAL_VALUE",
        path || "(root)",
        `${path || "value"} must be exactly '${schemaNode.const}'`,
        { expected: schemaNode.const, actual: value }
      );
    }
  }

  if (Array.isArray(schemaNode.enum)) {
    if (!schemaNode.enum.includes(value)) {
      addError(
        "INVALID_ENUM_VALUE",
        path || "(root)",
        `${path || "value"} must be one of: ${schemaNode.enum.join(", ")}`,
        { allowed_values: schemaNode.enum, actual: value }
      );
    }
  }

  if (schemaNode.type === "string") {
    if ("minLength" in schemaNode && typeof value === "string") {
      if (value.length < schemaNode.minLength) {
        addError(
          "MIN_LENGTH_VIOLATION",
          path || "(root)",
          `${path || "value"} must be at least ${schemaNode.minLength} characters long`,
          { min_length: schemaNode.minLength, actual_length: value.length }
        );
      }
    }
  }

  if (schemaNode.type === "array" && Array.isArray(value)) {
    if ("minItems" in schemaNode && value.length < schemaNode.minItems) {
      addError(
        "MIN_ITEMS_VIOLATION",
        path || "(root)",
        `${path || "array"} must contain at least ${schemaNode.minItems} items`,
        { min_items: schemaNode.minItems, actual_count: value.length }
      );
    }

    if (schemaNode.uniqueItems === true) {
      const seen = new Set();
      for (let i = 0; i < value.length; i++) {
        const itemKey = JSON.stringify(value[i]);
        if (seen.has(itemKey)) {
          addError(
            "DUPLICATE_ARRAY_ITEM",
            `${path}[${i}]`,
            `${path}[${i}] must be unique`,
            { actual_value: value[i] }
          );
        } else {
          seen.add(itemKey);
        }
      }
    }

    if (schemaNode.items) {
      for (let i = 0; i < value.length; i++) {
        validateAgainstSchema(value[i], schemaNode.items, `${path}[${i}]`);
      }
    }
  }

  if (schemaNode.type === "object" && value && typeof value === "object" && !Array.isArray(value)) {
    const props = schemaNode.properties || {};
    const required = Array.isArray(schemaNode.required) ? schemaNode.required : [];

    for (const reqField of required) {
      if (!(reqField in value)) {
        addError(
          "MISSING_REQUIRED_FIELD",
          path ? pathJoin(path, reqField) : reqField,
          `Missing required field: ${path ? pathJoin(path, reqField) : reqField}`
        );
      }
    }

    if (schemaNode.additionalProperties === false) {
      for (const key of Object.keys(value)) {
        if (!(key in props)) {
          addError(
            "UNEXPECTED_FIELD",
            path ? pathJoin(path, key) : key,
            `Unexpected field not allowed by schema: ${path ? pathJoin(path, key) : key}`,
            { actual_key: key }
          );
        }
      }
    }

    for (const [key, propSchema] of Object.entries(props)) {
      if (key in value) {
        validateAgainstSchema(value[key], propSchema, path ? pathJoin(path, key) : key);
      }
    }
  }
}

// --- Run validation ---
validateAgainstSchema(outputData, schema, "");

// --- Final status ---
const validation_status = errors.length === 0 ? "PASS" : "FAIL";

// Emit original parsed response envelope plus validation result
return [
  {
    json: {
      ...parsedResponse,
      output_validation: {
        validation_status,
        error_count: errors.length,
        errors
      }
    }
  }
];

const actualArtifact = $input.first().json;

const expectedFixture = {
  sde_version: "v0_1",
  output_id: "F01_OUT",
  source_input_id: "F01",
  question_groups: [
    {
      group_id: "G01",
      group_name: "GOALS",
      group_purpose: "Clarify the primary objective of the assistant and distinguish immediate value from later ambitions.",
      questions: [
        {
          question_id: "Q01",
          question_text: "What is the single most important outcome you want the first version of this assistant to achieve for the operations team?",
          question_intent: "Reduces primary-objective ambiguity by forcing prioritization of the initial business goal.",
          priority: "HIGH"
        },
        {
          question_id: "Q02",
          question_text: "Is the first version intended mainly to answer SOP questions, reduce response time, reduce staff workload, or improve consistency of internal guidance?",
          question_intent: "Clarifies which success dimension matters most so downstream design is not based on a vague improvement goal.",
          priority: "HIGH"
        }
      ]
    },
    {
      group_id: "G02",
      group_name: "SCOPE",
      group_purpose: "Separate the initial advisory phase from possible future automation and define what is in or out of scope.",
      questions: [
        {
          question_id: "Q03",
          question_text: "For phase one, should the assistant be limited to answering questions only, with no ability to create or modify tickets?",
          question_intent: "Resolves phase-one execution-scope ambiguity and prevents advisory and action-taking behavior from being mixed too early.",
          priority: "HIGH"
        },
        {
          question_id: "Q04",
          question_text: "Is automatic maintenance ticket creation a future possibility only, or is it expected to be part of the near-term rollout plan?",
          question_intent: "Clarifies whether ticket automation is strategic future scope or an immediate design requirement.",
          priority: "HIGH"
        },
        {
          question_id: "Q05",
          question_text: "Which types of SOP questions should the assistant be allowed to answer in the first release, and which topics should remain out of scope?",
          question_intent: "Defines content boundaries so the assistant is not assumed to cover all operational knowledge areas by default.",
          priority: "MEDIUM"
        }
      ]
    },
    {
      group_id: "G03",
      group_name: "CONSTRAINTS",
      group_purpose: "Surface practical and policy limits that should shape the first version of the assistant.",
      questions: [
        {
          question_id: "Q06",
          question_text: "Are there compliance, policy, security, or internal governance rules that would limit what this assistant can access or do?",
          question_intent: "Surfaces formal restrictions that may block certain capabilities before solution design begins.",
          priority: "HIGH"
        },
        {
          question_id: "Q07",
          question_text: "Does the organization require human approval before any AI-generated action can affect an operational system or maintenance workflow?",
          question_intent: "Clarifies approval constraints and whether action-taking behavior must always remain gated by a human.",
          priority: "HIGH"
        },
        {
          question_id: "Q08",
          question_text: "Is there a preferred rollout constraint such as internal-only access, limited pilot users, or read-only behavior for the first release?",
          question_intent: "Identifies rollout-limiting constraints that define the safe boundary of the first deployment.",
          priority: "MEDIUM"
        }
      ]
    },
    {
      group_id: "G04",
