function esc(text) {
  if (text === null || text === undefined) return "";
  return String(text)
    .replace(/\\/g, "\\textbackslash{}")
    .replace(/&/g, "\\&")
    .replace(/%/g, "\\%")
    .replace(/\$/g, "\\$")
    .replace(/#/g, "\\#")
    .replace(/_/g, "\\_")
    .replace(/{/g, "\\{")
    .replace(/}/g, "\\}")
    .replace(/~/g, "\\textasciitilde{}")
    .replace(/\^/g, "\\textasciicircum{}");
}

// Only convert single-quoted phrases into proper LaTeX quotes.
// Example: 'trusted' -> \enquote{trusted}
// Leaves everything else alone.
function escWithSmartQuotes(text) {
  const escaped = esc(text);
  return escaped.replace(/'([^']+)'/g, "\\enquote{$1}");
}

