// --- Helpers ---
function addCheck(name, passed, detail) {
  comparison_checks.push({
    check_name: name,
    severity: "HARD",
    passed,
    detail
  });

  if (!passed) {
    comparison_errors.push({
      check_name: name,
      detail
    });
  }
}

function addSoftCheck(name, passed, detail) {
  comparison_checks.push({
    check_name: name,
    severity: "SOFT",
    passed,
    detail
  });

  if (!passed) {
    comparison_notes.push(`[SOFT] ${name}: ${detail}`);
  }
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(arr) {
  return [...new Set(arr)];
}

function extractGroupNames(output) {
  return asArray(output.question_groups)
    .map(group => group.group_name)
    .filter(Boolean);
}

