const actualGroups = asArray(actual.question_groups);
const expectedGroups = asArray(expected.question_groups);

const actualGroupNames = unique(extractGroupNames(actual));
const expectedGroupNames = unique(extractGroupNames(expected));

const actualAmbiguityFlags = asArray(actual.ambiguity_flags);
const expectedAmbiguityFlags = asArray(expected.ambiguity_flags);

const actualCompletenessNotes = asArray(actual.completeness_notes);
const expectedCompletenessNotes = asArray(expected.completeness_notes);

// --- 1. sde_version alignment ---
addCheck(
  "sde_version_match",
  actual.sde_version === expected.sde_version,
  actual.sde_version === expected.sde_version
    ? `sde_version matched: ${actual.sde_version}`
    : `Mismatch: actual=${actual.sde_version ?? null}, expected=${expected.sde_version ?? null}`
);

// --- 2. Question group count sanity ---
addCheck(
  "question_group_count_nonzero",
  actualGroups.length > 0,
  actualGroups.length > 0
    ? `Actual output has ${actualGroups.length} question groups`
    : "Actual output has no question groups"
);

// --- 3. Required expected group-name coverage ---
const missingExpectedGroups = expectedGroupNames.filter(
  name => !actualGroupNames.includes(name)
);
addCheck(
  "expected_group_names_covered",
  missingExpectedGroups.length === 0,
  missingExpectedGroups.length === 0
    ? `All expected group names were present: ${expectedGroupNames.join(", ")}`
    : `Missing expected group names: ${missingExpectedGroups.join(", ")}`
);

// --- 4. Generated group-name set sanity ---
addCheck(
  "actual_group_name_count_reasonable",
  actualGroupNames.length >= Math.max(1, expectedGroupNames.length - 1),
  `Actual group names: ${actualGroupNames.join(", ")}`
);

// --- 5. Every actual group has at least one question ---
const emptyGroups = actualGroups
  .filter(group => !Array.isArray(group.questions) || group.questions.length === 0)
  .map(group => group.group_name || group.group_id || "(unknown)");

addCheck(
  "no_empty_actual_question_groups",
  emptyGroups.length === 0,
  emptyGroups.length === 0
    ? "All actual groups contain at least one question"
    : `Empty actual groups: ${emptyGroups.join(", ")}`
);

// --- 6. source_input_id alignment (SOFT only) ---
addSoftCheck(
  "source_input_id_alignment",
  actual.source_input_id === expected.source_input_id,
  actual.source_input_id === expected.source_input_id
    ? `source_input_id matched: ${actual.source_input_id}`
    : `Difference is acceptable for live-vs-fixture comparison: actual=${actual.source_input_id ?? null}, expected=${expected.source_input_id ?? null}`
);

// --- 7. output_id alignment (SOFT only) ---
addSoftCheck(
  "output_id_alignment",
  actual.output_id === expected.output_id,
  actual.output_id === expected.output_id
    ? `output_id matched: ${actual.output_id}`
    : `Difference is acceptable for live-vs-fixture comparison: actual=${actual.output_id ?? null}, expected=${expected.output_id ?? null}`
);

// --- 8. Ambiguity flag presence alignment (SOFT) ---
addSoftCheck(
  "ambiguity_flag_presence_alignment",
  (expectedAmbiguityFlags.length === 0 && actualAmbiguityFlags.length === 0) ||
  (expectedAmbiguityFlags.length > 0 && actualAmbiguityFlags.length > 0),
  `expected ambiguity_flags count=${expectedAmbiguityFlags.length}, actual count=${actualAmbiguityFlags.length}`
);

// --- 9. Completeness notes presence alignment (SOFT) ---
addSoftCheck(
  "completeness_notes_presence_alignment",
  (expectedCompletenessNotes.length === 0 && actualCompletenessNotes.length === 0) ||
  (expectedCompletenessNotes.length > 0 && actualCompletenessNotes.length > 0),
  `expected completeness_notes count=${expectedCompletenessNotes.length}, actual count=${actualCompletenessNotes.length}`
);

// --- Optional general notes ---
if (actualGroups.length !== expectedGroups.length) {
  comparison_notes.push(
    `Actual question group count (${actualGroups.length}) differs from expected fixture (${expectedGroups.length}). This may still be acceptable if coverage is strong.`
  );
}

if (actualAmbiguityFlags.length !== expectedAmbiguityFlags.length) {
  comparison_notes.push(
    `Actual ambiguity_flags count (${actualAmbiguityFlags.length}) differs from expected fixture (${expectedAmbiguityFlags.length}).`
  );
}

if (actualCompletenessNotes.length !== expectedCompletenessNotes.length) {
