function nonEmpty(value) {
  return value !== undefined && value !== null && String(value).trim() !== "";
}

function asTrimmedString(value) {
  if (!nonEmpty(value)) return "";
  return String(value).trim();
}

function buildInputId(ts, intakeSource = "INPUT") {
  const d = ts ? new Date(ts) : new Date();
  const iso = isNaN(d.getTime()) ? new Date().toISOString() : d.toISOString();
  const compact = iso.replace(/[-:TZ.]/g, "").slice(0, 14);
  const prefix = String(intakeSource || "INPUT").toLowerCase();
  return `${prefix}_${compact}`;
}

function normalizeStringArray(value) {
  if (Array.isArray(value)) {
    return value
      .map((v) => String(v).trim())
      .filter((v) => v.length > 0);
  }

  if (nonEmpty(value)) {
    // Preserve a single raw text value as one array item rather than inventing a split.
    return [String(value).trim()];
  }

  return [];
}

