if (!input.response_envelope.output || typeof input.response_envelope.output !== "object") {
  throw new Error("SDE Handoff Preparation: missing response_envelope.output object.");
}

if (!input.artifact_metadata || typeof input.artifact_metadata !== "object") {
  throw new Error("SDE Handoff Preparation: missing artifact_metadata object.");
}

const sourceInputId = input.artifact_metadata.source_input_id;
const outputId = input.artifact_metadata.output_id;
const generatedAtUtc = input.artifact_metadata.generated_at_utc;

if (!sourceInputId || !outputId || !generatedAtUtc) {
  throw new Error("SDE Handoff Preparation: artifact_metadata is missing required identity fields.");
}

return [
  {
    json: {
      artifact_type: "SDE_HANDOFF_OBJECT_FOR_AFE",
      artifact_version: "v0_1",
      artifact_status: "handoff_ready",
      handoff_metadata: {
        from_tool: "SDE",
        to_tool: "AFE",
        source_input_id: sourceInputId,
        source_output_id: outputId,
        generated_at_utc: generatedAtUtc
      },
      sde_output: input.response_envelope.output
    }
  }
];
